import React from 'react';
import { Route, NavLink, Switch, Link, HashRouter as Router } from 'react-router-dom';
import './App.css';
import Home from './templates/Home';
import About from './templates/About';
import Work from './templates/Work';
import WorkDetail from './templates/WorkDetail';
import Contact from './templates/Contact';

function App() {
  return (
    <div className="App">
      <Router>
        <nav className="navbar navbar-expand-lg navbar-light nav-bg">
        <Link className="navbar-brand nav-logo mt-3 mb-3" to="/"></Link>
        <div className="col-md-11 mt-3 mb-3 p-0">
          <ul className="navbar-nav">
            <li className="nav-item">
              <NavLink exact activeClassName="active" className="nav-link" to="/">Home</NavLink>
            </li>
            <li className="nav-item">
              <NavLink activeClassName="active" className="nav-link" to="/about">About</NavLink>
            </li>
            <li className="nav-item">
              <NavLink activeClassName="active" className="nav-link" to="/work">Work</NavLink>
            </li>
            <li className="nav-item">
              <NavLink activeClassName="active" className="nav-link" to="/contact">Contact</NavLink>
            </li>
          </ul>
        </div>
        </nav>
        <Switch>
          <Route exact path="/" component={Home} />
          <Route path="/about" component={About} />
          <Route path="/work" component={Work} />
          <Route path="/workdetail/:id" component={WorkDetail} />
          <Route path="/contact" component={Contact} />
        </Switch>
      </Router>
    </div>
  );
}
export default App;
