import React from 'react';

function ImageComponent(props) {
    const images = require.context('../assets', true);
    const selectedImg = images(`./${props.image}`);
    const selectedName = `${props.name}`;
    const shot = `${props.ele}`;
    var imageEle;
    if (shot === "shots"){
       imageEle =  <img className="card-img-top" height="500px" src = {selectedImg} alt = {selectedName}/>;
    } else{
        imageEle =  <img className="card-img-top" src = {selectedImg} alt = {selectedName}/>;
    }

    return (
        imageEle
    )
}

export default ImageComponent;