import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import ImageComponent from './ImageComponent';
import loader from '../assets/loader.gif';

function Work() {
  const [error, setError] = useState(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const [items, setItems] = useState([]);

  useEffect(() => {
    fetch("/data.json")
      .then(res => res.json())
      .then(
        (result) => {
          setIsLoaded(true);
          setItems(result);
        },
        (error) => {
          setIsLoaded(true);
          setError(error);
        }
      )
  }, [])

  if (error) {
    return <div>Error: {error.message}</div>;
  } else if (!isLoaded) {
    return <div className="text-center m-5"><img className="" width="50px"  src = {loader} alt='loader'/></div>;
  } else {
    return (
      <div className="container-fluid">
        <div className="p-4">
          <header className="text-center">
            <h1 className="header-top">My Work</h1>
          </header>
          <section>
            {items.map(item => (
                <div className="row card-parent" key={item.name}>
                  <div className="col-md-4 card-child">
                    <Link className="" to={'/workdetail/'+item.id}>
                      <ImageComponent image={item.image} name={item.name}/>
                    </Link>
                    <div className="heading">
                      {item.name}
                    </div>
                    <div className="content">
                      <p>{item.desc}</p>
                    </div>
                  </div>
                  <div className="col-md-8 card-child">
                    <Link className="" to={'/workdetail/'+item.id}>
                       <ImageComponent ele="shots" image={item.shot} name={item.name}/>
                    </Link>
                  </div>
                </div>
            ))}
          </section> 
        </div>
      </div>
    );
  }
}

export default Work;