import React, { useState, useEffect } from 'react';
import BigImageComponent from './BigImageComponent';
import { Link } from 'react-router-dom';
import loader from '../assets/loader.gif';

function WorkDetail(props) {
  const [error, setError] = useState(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const [screens, setScreens] = useState([]);
  const [checkVideo, setVideo] = useState([]);
  const eleid = props.match.params.id;
  
  useEffect(() => {
    fetch("/data.json")
      .then(res => res.json())
      .then(
        (result) => {
          setIsLoaded(true);
          setScreens(result[eleid].screenshots);
          setVideo(result[eleid].checkvideo);
        },
        (error) => {
          setIsLoaded(true);
          setError(error);
        }
      )
  }, [eleid])
  if (error) {
    return <div>Error: {error.message}</div>;
  } else if (!isLoaded) {
    return <div className="text-center m-5"> <img className="" width="50px"  src = {loader} alt='loader'/></div>;
  } else{
    return (
      <div className="container-fluid">
        <div className="p-4">
            <div className="mb-2">
              <Link className="btn" to={'/work'}>Back to work</Link>
            </div>
            {
                screens.map(item => (
                  <div className="card mb-2">
                    <div className="card-body">  
                      <BigImageComponent image = {item} setVideo = {checkVideo} />
                    </div>
                  </div>
                  ))
            }
        </div>
      </div>     
    );
  }
    
    
  
}

export default WorkDetail;