import React from 'react';
import suntrustVideo from '../assets/screens/suntrustpages.mp4';

function BigImageComponent(props) {
    const imageContext = require.context('../assets/screens/', true);
    const selectedImg = imageContext(`./${props.image}`);
    console.log(selectedImg)
    console.log(props.setVideo)

    return (
        props.setVideo?(
        <video autoplay='true' controls width="100%" height="100%">
            <source src={suntrustVideo} type="video/mp4"></source>
        </video>
        ) : (
        <figure>
            <img className="card-img mx-auto d-block" src = {selectedImg} alt='test'/>
        </figure>
        )
        
    )
}

export default BigImageComponent;